import { Component, Input } from '@angular/core';

@Component({
  selector: 'app-score-card',
  templateUrl: './score-card.component.html'
})
export class ScoreCardComponent {
  @Input() title = 'ATS Score';
  @Input() score = 0;

  get tone(): string {
    if (this.score >= 80) {
      return 'text-[#16a34a]';
    }
    if (this.score >= 60) {
      return 'text-[#f59e0b]';
    }
    return 'text-[#ef4444]';
  }
}
<div class="shell-card p-6">
  <p class="eyebrow">{{ title }}</p>
  <div class="mt-5 flex items-end justify-between">
    <div>
      <p class="section-title text-5xl" [ngClass]="tone">{{ score }}</p>
      <p class="mt-2 text-sm text-[#667085]">Out of 100</p>
    </div>
    <div class="h-16 w-16 rounded-full border-8 border-[#e7e9f6]" [ngClass]="{
      'border-t-[#16a34a]': score >= 80,
      'border-t-[#f59e0b]': score >= 60 && score < 80,
      'border-t-[#ef4444]': score < 60
    }"></div>
  </div>
</div>
